using System.ComponentModel;
using System.Text.Json;
using ModelContextProtocol.Server;

[McpServerResourceType]
public static class ConfigResources
{
    [McpServerResource(
        UriTemplate = "config://app",
        Name = "App Configuration",
        MimeType = "application/json"),
     Description("Returns the current application configuration as JSON.")]
    public static string GetAppConfig()
    {
        var config = new
        {
            AppName = "HttpMcpServer",
            Version = "1.0.0",
            Environment = Environment.GetEnvironmentVariable("ASPNETCORE_ENVIRONMENT") ?? "Production",
            MaxRetries = 3,
            TimeoutSeconds = 30,
            Features = new { EnableCaching = true, EnableLogging = true }
        };

        return JsonSerializer.Serialize(config, new JsonSerializerOptions { WriteIndented = true });
    }

    [McpServerResource(
        UriTemplate = "config://endpoints",
        Name = "API Endpoints",
        MimeType = "application/json"),
     Description("Returns the list of configured API endpoints.")]
    public static string GetEndpoints()
    {
        var endpoints = new[]
        {
            new { Name = "Users",    Url = "https://api.example.com/users" },
            new { Name = "Products", Url = "https://api.example.com/products" },
            new { Name = "Orders",   Url = "https://api.example.com/orders" }
        };

        return JsonSerializer.Serialize(endpoints, new JsonSerializerOptions { WriteIndented = true });
    }
}

using System.ComponentModel;
using ModelContextProtocol.Server;

[McpServerToolType]
public static class GreetingTools
{
    [McpServerTool, Description("Returns a friendly greeting for the given name.")]
    public static string Greet(
        [Description("The name of the person to greet")] string name)
    {
        return $"Hello, {name}! Welcome to the HTTP MCP server.";
    }

    [McpServerTool, Description("Returns the current server time in UTC.")]
    public static string GetServerTime()
    {
        return $"Server time (UTC): {DateTime.UtcNow:O}";
    }
}

